import{_ as e,o as r,c as d,a6 as a}from"./chunks/framework.Bf5o6qNq.js";const b=JSON.parse('{"title":"《禁忌的 Show》企劃概要","description":"","frontmatter":{"title":"《禁忌的 Show》企劃概要"},"headers":[],"relativePath":"guide/企劃概要.md","filePath":"guide/企劃概要.md"}'),o={name:"guide/企劃概要.md"};function n(l,t,i,s,h,c){return r(),d("div",null,[...t[0]||(t[0]=[a('<div class="tip custom-block"><p class="custom-block-title">正式發行與資料來源</p><p><strong>正式發行規劃</strong>：以 <strong>Unity</strong> 建置、目標上架 <strong>Steam</strong>（分級／合規依發行區域與商店政策）。</p><p><strong>準則來源</strong>：本頁複製自倉庫根目錄 <code>禁忌的Show_遊戲企劃書.md</code>（與本 Wiki 資料夾同層：<code>b041_NSFWShowAiProject/</code>）。若兩處不一致，以該檔案為準。</p></div><hr><h1 id="《禁忌的show》遊戲企劃書" tabindex="-1">《禁忌的Show》遊戲企劃書 <a class="header-anchor" href="#《禁忌的show》遊戲企劃書" aria-label="Permalink to &quot;《禁忌的Show》遊戲企劃書&quot;">​</a></h1><p><strong>文件版本</strong>：初稿（依現有專案內容整理）<br><strong>最後更新</strong>：2026 年 4 月</p><hr><h2 id="一、企劃概要" tabindex="-1">一、企劃概要 <a class="header-anchor" href="#一、企劃概要" aria-label="Permalink to &quot;一、企劃概要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td>遊戲名稱</td><td>禁忌的Show</td></tr><tr><td>類型</td><td>戀愛實境綜藝題材之 <strong>成人向</strong> 戀愛模擬遊戲（含小遊戲、數值與多結局要素）</td></tr><tr><td>遊戲內時間軸</td><td><strong>14 天</strong></td></tr><tr><td>核心目標</td><td>在節目中與其他男性競爭，提升心儀女主角的好感，最終達成 <strong>成功配對</strong></td></tr><tr><td>技術原型</td><td>瀏覽器端 HTML / JavaScript 小型原型（<code>小游戲測試</code>），以 <code>localStorage</code> 保存進度</td></tr></tbody></table><hr><h2 id="二、世界觀與故事前提" tabindex="-1">二、世界觀與故事前提 <a class="header-anchor" href="#二、世界觀與故事前提" aria-label="Permalink to &quot;二、世界觀與故事前提&quot;">​</a></h2><h3 id="_2-1-背景設定-依《故事背景與設定》" tabindex="-1">2.1 背景設定（依《故事背景與設定》） <a class="header-anchor" href="#_2-1-背景設定-依《故事背景與設定》" aria-label="Permalink to &quot;2.1 背景設定（依《故事背景與設定》）&quot;">​</a></h3><p>玩家為某成人影音平台（企劃中稱「A 片公司」）的 <strong>長期 VIP</strong>，某日收到官方邀請，參與全新實境企劃 <strong>「禁忌的 SHOW」</strong>。節目於封閉 <strong>園區</strong> 內拍攝，玩家須與多名男性來賓競爭，爭取與多位女主角互動與配對的機會。</p><p>企劃書中可採用的敘事補強方向（文件內已列舉）包括：</p><ul><li><strong>選拔理由</strong>：幸運抽選、VIP 積分／消費排行、或個人成長動機等。</li><li><strong>參加動機</strong>：獎金、簽約／曝光機會、情感學習與自我突破等。</li><li><strong>節目命名</strong>：可呼應「打破傳統戀綜禁忌」或「禁忌園區」等意象。</li></ul><h3 id="_2-2-調性" tabindex="-1">2.2 調性 <a class="header-anchor" href="#_2-2-調性" aria-label="Permalink to &quot;2.2 調性&quot;">​</a></h3><ul><li>日間以 <strong>競賽／破冰／訓練</strong> 為主；夜間延伸至 <strong>約會卡、情境關卡、親密向 CG</strong> 等成人向演出（實際分級與規範由發行區域法令與平台政策決定）。</li></ul><hr><h2 id="三、角色構成" tabindex="-1">三、角色構成 <a class="header-anchor" href="#三、角色構成" aria-label="Permalink to &quot;三、角色構成&quot;">​</a></h2><h3 id="_3-1-女主角-5-名" tabindex="-1">3.1 女主角（5 名） <a class="header-anchor" href="#_3-1-女主角-5-名" aria-label="Permalink to &quot;3.1 女主角（5 名）&quot;">​</a></h3><p>專案中已定義類型標籤與 <strong>魅力／廚藝／體力</strong> 傾向（用於數值加成與劇情傾向，非絕對戰力）：</p><table tabindex="0"><thead><tr><th>角色</th><th style="text-align:center;">魅力</th><th style="text-align:center;">廚藝</th><th style="text-align:center;">體力</th><th>備註（類型意象）</th></tr></thead><tbody><tr><td>搖滾少女</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td style="text-align:center;">C</td><td>視覺與人設見「搖滾／龐克」系提示詞</td></tr><tr><td>清純少女</td><td style="text-align:center;">C</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td>清純、料理向</td></tr><tr><td>運動少女</td><td style="text-align:center;">C</td><td style="text-align:center;">C</td><td style="text-align:center;">A</td><td>體育、競技向</td></tr><tr><td>高冷大姐姐</td><td style="text-align:center;">B</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td>貴氣／大小姐系延伸</td></tr><tr><td>地雷女</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td style="text-align:center;">B</td><td>地雷系人設</td></tr></tbody></table><h3 id="_3-2-男性競爭者-3-名-ai" tabindex="-1">3.2 男性競爭者（3 名 AI） <a class="header-anchor" href="#_3-2-男性競爭者-3-名-ai" aria-label="Permalink to &quot;3.2 男性競爭者（3 名 AI）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th style="text-align:center;">魅力</th><th style="text-align:center;">廚藝</th><th style="text-align:center;">體力</th><th>定位</th></tr></thead><tbody><tr><td>暖男</td><td style="text-align:center;">B</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td>廚藝強、親和</td></tr><tr><td>高冷男</td><td style="text-align:center;">A</td><td style="text-align:center;">C</td><td style="text-align:center;">B</td><td>魅力強、走位偏冷</td></tr><tr><td>體育男</td><td style="text-align:center;">B</td><td style="text-align:center;">C</td><td style="text-align:center;">A</td><td>體力強、運動項目優勢</td></tr></tbody></table><p>玩家男主角同樣具備 <strong>廚藝／體力／魅力</strong> 三維（等級 C／B／A），影響各小遊戲難度與勝率。</p><hr><h2 id="四、核心系統-依現有原型" tabindex="-1">四、核心系統（依現有原型） <a class="header-anchor" href="#四、核心系統-依現有原型" aria-label="Permalink to &quot;四、核心系統（依現有原型）&quot;">​</a></h2><h3 id="_4-1-日程結構" tabindex="-1">4.1 日程結構 <a class="header-anchor" href="#_4-1-日程結構" aria-label="Permalink to &quot;4.1 日程結構&quot;">​</a></h3><p>每日分為三個時段，主頁（<code>index.html</code>）集中顯示 <strong>天數、當前時段、約會卡數量、好感度表</strong>：</p><ol><li><strong>早上</strong>：破冰小遊戲（完成後進入中午）。</li><li><strong>中午</strong>：自由活動（訓練能力、隨機遭遇女主角小幅好感變化）。</li><li><strong>晚上</strong>：夜晚活動（消耗約會卡、進入酒吧／泳池／溫泉等分支，可銜接親密 CG；第 14 天夜後導向結局）。</li></ol><h3 id="_4-2-男主角成長" tabindex="-1">4.2 男主角成長 <a class="header-anchor" href="#_4-2-男主角成長" aria-label="Permalink to &quot;4.2 男主角成長&quot;">​</a></h3><ul><li><strong>中午訓練</strong>：廚藝訓練、健身（體力）、練舞（魅力）。</li><li>同一能力累積訓練次數達門檻可 <strong>C → B → A</strong> 升級。</li><li>訓練時可能 <strong>撞見隨機女主角</strong>，依該角色對應能力偏好放大或縮小好感加成。</li></ul><h3 id="_4-3-好感度與約會資源" tabindex="-1">4.3 好感度與約會資源 <a class="header-anchor" href="#_4-3-好感度與約會資源" aria-label="Permalink to &quot;4.3 好感度與約會資源&quot;">​</a></h3><ul><li><strong>好感度</strong>：每位女主角對「玩家、暖男、高冷男、體育男」各自累積；介面區分 <strong>總累積</strong> 與 <strong>當日累積</strong>。</li><li><strong>約會卡</strong>：夜晚行動與競爭有關（各男性持有張數於主頁顯示），用於推進夜間事件。</li></ul><h3 id="_4-4-日結與結局" tabindex="-1">4.4 日結與結局 <a class="header-anchor" href="#_4-4-日結與結局" aria-label="Permalink to &quot;4.4 日結與結局&quot;">​</a></h3><ul><li>非最終日夜晚流程結束後進入 <strong>日結</strong>（<code>day-result.html</code>），再返回隔日主頁。</li><li><strong>第 14 天</strong> 後進入 <strong>結局</strong>（<code>ending.html</code>），並可連結 <strong>結局 CG</strong>（<code>ending-cg.html</code>）。</li></ul><hr><h2 id="五、小遊戲與玩法一覽" tabindex="-1">五、小遊戲與玩法一覽 <a class="header-anchor" href="#五、小遊戲與玩法一覽" aria-label="Permalink to &quot;五、小遊戲與玩法一覽&quot;">​</a></h2><h3 id="_5-1-早上破冰-隨機三選一" tabindex="-1">5.1 早上破冰（隨機三選一） <a class="header-anchor" href="#_5-1-早上破冰-隨機三選一" aria-label="Permalink to &quot;5.1 早上破冰（隨機三選一）&quot;">​</a></h3><p>由 <code>morning-games.html</code> 隨機擇一進入，並帶入玩家與 AI 的等級參數：</p><table tabindex="0"><thead><tr><th>遊戲</th><th>對應能力</th><th>設計文件／路徑</th></tr></thead><tbody><tr><td>烤肉小遊戲</td><td>廚藝</td><td><code>烤肉小遊戲設計.md</code>、<code>烤肉小遊戲/</code></td></tr><tr><td>舞蹈節拍秀</td><td>魅力</td><td><code>舞蹈節拍秀設計.md</code>、<code>舞蹈節拍秀/</code></td></tr><tr><td>跑酷競賽</td><td>體力</td><td><code>runner-race.html</code></td></tr></tbody></table><p><strong>機制摘要</strong>：</p><ul><li><strong>烤肉</strong>：類魔物獵人烤肉，於目標熟度（3／5／7 分）判定區停手；廚藝影響判定窗。多輪積分排名。</li><li><strong>舞蹈節拍秀</strong>：方向鍵節拍、輪流回合、魅力影響判定窗與分數加成。</li><li><strong>跑酷</strong>：與 AI 競速（細節見實作頁面）。</li></ul><h3 id="_5-2-其他已建檔小遊戲" tabindex="-1">5.2 其他已建檔小遊戲 <a class="header-anchor" href="#_5-2-其他已建檔小遊戲" aria-label="Permalink to &quot;5.2 其他已建檔小遊戲&quot;">​</a></h3><table tabindex="0"><thead><tr><th>內容</th><th>說明</th></tr></thead><tbody><tr><td>乒乓球小遊戲</td><td>淘汰賽制、體力等級影響 AI 與殺球；見 <code>乒乓球小遊戲設計.md</code>。可作為日後擴充早午晚其中一段。</td></tr><tr><td>泳池排球、酒吧骰子／吹牛、溫泉按摩序列</td><td>串接於 <strong>夜晚活動</strong>（<code>night-activity.html</code>），完成條件後可導向 <strong>親密 CG</strong> 或日結／結局。</td></tr></tbody></table><h3 id="_5-3-演出與-cg" tabindex="-1">5.3 演出與 CG <a class="header-anchor" href="#_5-3-演出與-cg" aria-label="Permalink to &quot;5.3 演出與 CG&quot;">​</a></h3><ul><li><strong>親密劇情 CG</strong>（<code>intimate-cg.html</code>）：依女主角與場景參數切換。</li><li><strong>結局 CG</strong>（<code>ending-cg.html</code>）：依配對結果或選定女主角展示。</li><li>美術量產支援：<code>提示詞文件</code> 下依角色／場景分類的 AI 繪圖提示詞（男生、女生、場景等多套風格）。</li></ul><hr><h2 id="六、場景與美術方向-依提示詞結構" tabindex="-1">六、場景與美術方向（依提示詞結構） <a class="header-anchor" href="#六、場景與美術方向-依提示詞結構" aria-label="Permalink to &quot;六、場景與美術方向（依提示詞結構）&quot;">​</a></h2><ul><li><strong>場景</strong>：現代豪宅客廳、舞台聚光燈、跑道、溫泉旅館等（見 <code>場景提示詞</code>）。</li><li><strong>角色</strong>：依 archetype 分資料夾（搖滾／清純／運動／大小姐／地雷／男主角／暖男／高冷／健身教練等），含 Q 版與正比、多裝束狀態，便於統一世界觀與量產素材。</li></ul><hr><h2 id="七、目標受眾與產品定位" tabindex="-1">七、目標受眾與產品定位 <a class="header-anchor" href="#七、目標受眾與產品定位" aria-label="Permalink to &quot;七、目標受眾與產品定位&quot;">​</a></h2><ul><li><strong>主要受眾</strong>：成年玩家，熟悉戀愛模擬、綜藝戀愛梗與輕度操作小遊戲者。</li><li><strong>差異化</strong>：「戀綜＋數值養成＋多日流程」與「單日單局小遊戲」結合；長線以 <strong>14 天回圈</strong> 與 <strong>多角色好感競爭</strong> 拉長遊玩動機。</li><li><strong>開發階段現狀</strong>：核心迴圈與多個小遊戲已可遊玩與存檔；中午／夜晚與部分分支仍可在正式版擴寫劇本與演出。</li></ul><hr><h2 id="八、後續開發建議-與《故事背景與設定》對齊" tabindex="-1">八、後續開發建議（與《故事背景與設定》對齊） <a class="header-anchor" href="#八、後續開發建議-與《故事背景與設定》對齊" aria-label="Permalink to &quot;八、後續開發建議（與《故事背景與設定》對齊）&quot;">​</a></h2><ol><li><strong>劇本</strong>：固定其中一版「參加動機＋選拔機制」，撰寫完整序章與 NPC（製作人、主持）台詞。</li><li><strong>系統</strong>：時間分配、禮物／金錢或體力資源是否與訓練整合；淘汰制與否。</li><li><strong>內容</strong>：補齊 14 天每日差異事件、NG 與壞結局、True End 條件。</li><li><strong>技術</strong>：原型可遷移至正式引擎（如 Unity／WebGL）或整合後端，避免僅依瀏覽器本機儲存。</li><li><strong>合規</strong>：成人向販售區域、年齡驗證與內容標示。</li></ol><hr><h2 id="九、專案目錄對照-方便企劃與程式對接" tabindex="-1">九、專案目錄對照（方便企劃與程式對接） <a class="header-anchor" href="#九、專案目錄對照-方便企劃與程式對接" aria-label="Permalink to &quot;九、專案目錄對照（方便企劃與程式對接）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>路徑或檔案</th></tr></thead><tbody><tr><td>故事與世界觀</td><td><code>小游戲測試/故事背景與設定.md</code></td></tr><tr><td>主流程與存檔鍵</td><td><code>小游戲測試/index.html</code></td></tr><tr><td>小遊戲設計</td><td><code>烤肉小遊戲設計.md</code>、<code>乒乓球小遊戲設計.md</code>、<code>舞蹈節拍秀設計.md</code></td></tr><tr><td>美術提示詞</td><td><code>提示詞文件/</code></td></tr><tr><td>說明</td><td><code>README.md</code>（目前為專案占位，可改為完整專案說明）</td></tr></tbody></table><hr><h2 id="備註" tabindex="-1">備註 <a class="header-anchor" href="#備註" aria-label="Permalink to &quot;備註&quot;">​</a></h2><p>本企劃書依目前倉庫內既有文件與可執行原型整理；若之後變更角色名稱、天數或系統設計，應同步更新本文件與 <code>故事背景與設定.md</code>。</p>',60)])])}const u=e(o,[["render",n]]);export{b as __pageData,u as default};
